diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..cb7858962838 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4607,6 +4607,38 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
     }
+
+    // select (select X, Y, false), true, X --> X
+    // select (select X, Y, false), true, Y --> Y
+    // (select X, Y, false) is equivalent to (X && Y)
+    // So: (X && Y) ? true : X --> X  and  (X && Y) ? true : Y --> Y
+    Value *InnerCond, *InnerTV;
+    if (match(Cond, m_Select(m_Value(InnerCond), m_Value(InnerTV), m_Zero())) &&
+        match(TrueVal, m_One()) &&
+        (FalseVal == InnerCond || FalseVal == InnerTV))
+      return FalseVal;
+
+    // select X, true, (select Y, X, false) --> X
+    // select X, true, (select X, Y, false) --> X
+    // These work because:
+    //   select X, true, (Y && X) --> X  if inner TV == outer Cond
+    //   select X, true, (X && Y) --> X  if inner Cond == outer Cond
+    if (match(TrueVal, m_One())) {
+      Value *InnerCond, *InnerTV;
+      Constant *InnerFV;
+      // Check if FalseVal is a select with constant integer false value
+      // that doesn't contain poison or undef elements
+      if (match(FalseVal, m_Select(m_Value(InnerCond), m_Value(InnerTV), m_Constant(InnerFV))) &&
+          match(InnerFV, m_ZeroInt()) &&
+          !InnerFV->containsUndefOrPoisonElement()) {
+        // select Cond, true, (InnerCond, Cond, false) --> Cond
+        if (InnerTV == Cond)
+          return Cond;
+        // select Cond, true, (Cond, InnerTV, false) --> Cond
+        if (InnerCond == Cond)
+          return Cond;
+      }
+    }
   }

   // select ?, X, X -> X

